 1	import * as React from 'react';
 2	import { Button } from '@patternfly/react-core';
 3	import { useTranslation } from 'react-i18next';
 4	import { PipelineKind } from '../../types';
 5	import {
 6	  AccessReviewResourceAttributes,
 7	  useAccessReview,
 8	  useModal,
 9	} from '@openshift-console/dynamic-plugin-sdk';
10	import { PipelineRunModel } from '../../models';
11	import { startPipelineModal } from '../start-pipeline';
12	
13	type StateProps = {
14	  impersonate?: {
15	    kind: string;
16	    name: string;
17	    subprotocols: string[];
18	  };
19	};
20	
21	type PipelineStartButtonProps = {
22	  pipeline: PipelineKind;
23	  namespace: string;
24	};
25	
26	const PipelineStartButton: React.FC<PipelineStartButtonProps & StateProps> = ({
27	  pipeline,
28	  namespace,
29	  impersonate,
30	}) => {
31	  const { t } = useTranslation('plugin__pipelines-console-plugin');
32	  const launchModal = useModal();
33	
34	  const openPipelineModal = () => {
35	    launchModal(startPipelineModal, {
36	      pipeline,
37	    });
38	  };
39	  const defaultAccessReview: AccessReviewResourceAttributes = {
40	    group: PipelineRunModel.apiGroup,
41	    resource: PipelineRunModel.plural,
42	    namespace,
43	    verb: 'create',
44	  };
45	  const isAllowed = useAccessReview(defaultAccessReview, impersonate);
46	
47	  return (
48	    isAllowed && (
49	      <Button variant="secondary" onClick={openPipelineModal}>
50	        {t('Start')}
51	      </Button>
52	    )
53	  );
54	};
55	
56	export default PipelineStartButton;

